import{_ as r,C as a,o as i,c as s,j as d,a as t,E as c,a2 as n}from"./chunks/framework.C90q7Ucc.js";const b=JSON.parse('{"title":"tmux Runtime 生命周期","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/tmux-runtime-lifecycle.md","filePath":"architecture/tmux-runtime-lifecycle.md","lastUpdated":1781288769000}'),u={name:"architecture/tmux-runtime-lifecycle.md"};function m(l,e,x,p,h,C){const o=a("MermaidDiagram");return i(),s("div",null,[e[0]||(e[0]=d("h1",{id:"tmux-runtime-生命周期",tabindex:"-1"},[t("tmux Runtime 生命周期 "),d("a",{class:"header-anchor",href:"#tmux-runtime-生命周期","aria-label":'Permalink to "tmux Runtime 生命周期"'},"​")],-1)),e[1]||(e[1]=d("p",null,[t("本文描述 CodeLark 当前 tmux runtime 的完整链路。Codex 和 Claude Code 共用 "),d("code",null,"src/bridge/tmux/core.ts"),t(" 的 tmux API，差异只保留在各自 CLI 启动参数、会话文件发现和 JSONL 解析上。")],-1)),e[2]||(e[2]=d("h2",{id:"总览",tabindex:"-1"},[t("总览 "),d("a",{class:"header-anchor",href:"#总览","aria-label":'Permalink to "总览"'},"​")],-1)),c(o,{code64:""}),e[3]||(e[3]=n('<h2 id="公共-tmux-api" tabindex="-1">公共 tmux API <a class="header-anchor" href="#公共-tmux-api" aria-label="Permalink to &quot;公共 tmux API&quot;">​</a></h2><p>公共层在 <code>src/bridge/tmux/core.ts</code>，只负责稳定地驱动 tmux：</p><table tabindex="0"><thead><tr><th>API</th><th>职责</th></tr></thead><tbody><tr><td><code>hasSession</code></td><td>检查 tmux session 是否存在。</td></tr><tr><td><code>ensureDetachedSession</code></td><td>创建或按需重建 detached session。</td></tr><tr><td><code>capturePane</code></td><td>抓取屏幕，用于 <code>/tmux-screen</code>、ready 检测和调试。</td></tr><tr><td><code>sendActions</code></td><td>发送 literal 或特殊键；长文本自动走 buffer paste。</td></tr><tr><td><code>injectPromptIntoPane</code></td><td>多行 prompt 使用 paste-buffer + <code>M-Enter</code>，最后 <code>Enter</code> 提交。</td></tr><tr><td><code>sendInterrupt</code></td><td><code>/stop</code> 或 abort 时发送 <code>C-c</code>。</td></tr></tbody></table><p><code>src/bridge/tmux/runtime.ts</code> 是 runtime 级公共层，Codex 和 Claude 共用这些生命周期入口：</p><table tabindex="0"><thead><tr><th>API</th><th>职责</th></tr></thead><tbody><tr><td><code>runtimeTmuxSessionName</code> / <code>codexTmuxSessionName</code> / <code>claudeTmuxSessionName</code></td><td>统一 provider-owned tmux session 命名。</td></tr><tr><td><code>startRuntimeTmuxSession</code></td><td>以 `runtime=codex</td></tr><tr><td><code>waitForRuntimeTmuxReady</code></td><td>统一屏幕 ready 检测和 startup selection 处理；Codex 支持 update/goal/permission/generic selection 透传，Claude 支持 onboarding/trust 确认。</td></tr><tr><td><code>inspectRuntimeTmuxSession</code></td><td>统一检查 session 存在性、抓屏，并返回当前屏幕上的 selection prompt。</td></tr><tr><td><code>cleanupRuntimeTmuxSession</code></td><td>统一 best-effort 清理 provider-owned tmux session，供 <code>/clear</code> 和 <code>/t archive</code> 等生命周期操作调用。</td></tr></tbody></table><p>Codex 保留 <code>startCodexResumeTmuxSession</code> 和 <code>waitForCodexResumeTmuxReady</code> 作为兼容包装；Claude 的 <code>startClaudeTmuxSession</code> 也由 <code>src/bridge/tmux/runtime.ts</code> 提供，<code>src/runtime/claude/tmux-provider.ts</code> 只负责 prompt 注入、JSONL discovery 和 SSE/mirror 转换。</p><h2 id="codex-tmux-生命周期" tabindex="-1">Codex tmux 生命周期 <a class="header-anchor" href="#codex-tmux-生命周期" aria-label="Permalink to &quot;Codex tmux 生命周期&quot;">​</a></h2><h3 id="_1-thread-获取和注入" tabindex="-1">1. thread 获取和注入 <a class="header-anchor" href="#_1-thread-获取和注入" aria-label="Permalink to &quot;1. thread 获取和注入&quot;">​</a></h3><p>当用户把当前 Codex runtime 切到 <code>/provider tmux</code> 时，<code>src/bridge/command/provider-settings.ts</code> 先从 <code>BridgeSession.runtime.codex.threadId</code> 或 binding 推导已有 Codex thread。若没有 thread，会通过 <code>bootstrapCodexThreadLocally</code> 本地预创建 Codex thread，并把结果写回 <code>BridgeSession</code>。</p><p>完成 thread 解析后，<code>codexTmuxSessionName(threadId)</code> 生成 <code>codex_&lt;threadId&gt;</code>，<code>startCodexResumeTmuxSession</code> 用 <code>codex resume &lt;threadId&gt;</code> 启动 TUI。启动参数来自 <code>resolveSessionRuntimeConfig</code>，包括 model、sandbox、network、reasoning effort、mode 和 skipGitRepoCheck。</p><p>Codex tmux 还有一条隐式初始化路径：如果当前聊天的有效 Codex provider 已经是 <code>tmux</code>，但新会话还没有 <code>codex_thread_id</code> 或 tmux session，第一条普通 IM 消息会被 <code>src/bridge/host/manager.ts</code> 转成 <code>/tmux &lt;message&gt;</code>，并把 <code>autoRecoverProviderSession=true</code> 传给 <code>src/bridge/command/tmux.ts</code>。<code>ensureCodexTmuxSessionForProvider</code> 会在这个路径中自动执行本地 thread bootstrap、写回 <code>runtime.codex.threadId</code>、生成 <code>codex_&lt;threadId&gt;</code>、启动缺失的 Codex TUI，并在 ready 检测完成后再注入用户消息。</p><h3 id="_2-tui-启动和-ready-检测" tabindex="-1">2. TUI 启动和 ready 检测 <a class="header-anchor" href="#_2-tui-启动和-ready-检测" aria-label="Permalink to &quot;2. TUI 启动和 ready 检测&quot;">​</a></h3><p><code>buildCodexResumeTmuxCommand</code> 构造 Codex TUI shell command。Codex tmux 只允许使用全局 Codex CLI：resolver 不会回退到 <code>node_modules/.bin/codex</code> 或包内 <code>node_modules/.bin/codex</code>，显式 <code>CODELARK_CODEX_CLI_PATH</code> 也不能指向 <code>node_modules/.bin</code>，避免旧本地依赖反复弹更新提示。</p><p><code>waitForCodexResumeTmuxReady</code> 现在委托给 <code>waitForRuntimeTmuxReady(runtime=&#39;codex&#39;)</code> 周期性 <code>capturePane</code>，直到看到 Codex TUI ready prompt，或者达到 <code>CODELARK_CODEX_RESUME_TMUX_READY_TIMEOUT_MS</code>。如果启动时停在 update、goal、permission 或 generic selection，shared readiness 会把完整 selection prompt 发给 IM handler；没有 handler 时只返回未 ready，不自动按默认项。IM 下拉默认项来自 TUI 当前选择游标，若无法识别游标则使用 TUI 选项第一项；不会再把 update 固定成 <code>skip</code>，也不会把 goal 固定成 <code>cancel</code>。用户回调的 choice 会转换成 tmux 上的上下移动和 Enter，发送后继续 ready 检测，直到真正可输入才注入消息。</p><p>Codex/Claude 公共的终端控制字符清理和 Enter footer 检测集中在 <code>src/runtime/tui-screen.ts</code>；Codex TUI 的 Enter footer 检测统一支持 <code>Press enter to confirm ... esc ...</code> 和 <code>Press enter to continue</code>，但 selection parser 仍要求屏幕中存在选择游标和可解析选项，避免把普通 TUI 输出误判成 selection。没有 handler 时返回启动失败，避免误把 selection prompt 当作 idle prompt。</p><p>如果启动期 Codex update selection 选择了 <code>update_now</code>，真实 Codex CLI 通常会执行全局更新并退出当前 TUI。<code>startCodexResumeTmuxSession</code> 把“用户选择 <code>update_now</code> 后 provider-owned tmux session 消失”视为可恢复的更新完成信号：向用户发送一次强制可见 notice，然后最多重新启动同名 tmux session 一次，并重新进入 ready 检测。只有重启后的 TUI 进入 <code>ready</code>，调用方才会继续 provider 切换或 auto-forward 原始输入；如果重启仍失败，则按普通 launch failure 报告，避免重复循环。</p><p>ready 检测内部按一个显式 readiness gate 状态机运转；这个状态机只回答“现在是否可以把后续输入写进 provider-owned tmux pane”，不负责整条聊天任务的运行态。状态进入时的动作和触发条件如下：</p><table tabindex="0"><thead><tr><th>状态</th><th>进入动作</th><th>触发条件</th><th>下一跳</th></tr></thead><tbody><tr><td><code>starting</code></td><td>初始化 ready deadline 和命令追踪。</td><td>调用 <code>waitForRuntimeTmuxReady</code>。</td><td><code>polling</code>；如果 timeout 配成 0，直接 <code>ready</code>。</td></tr><tr><td><code>polling</code></td><td>抓取 tmux pane，并按当前屏幕分类。</td><td>启动检测开始，或 selection action 已发送后重新等待。</td><td>看到 idle prompt 转 <code>ready</code>；看到 selection 转 <code>waiting_selection</code> 或 <code>suspended</code>；抓屏失败且 session 消失转 <code>missing</code>；超时转 <code>timeout</code>。</td></tr><tr><td><code>suspended</code></td><td>停止 ready 检测，把当前 selection 交给外部路径处理。</td><td>禁止自动处理 selection、没有 IM handler、或 handler 没返回选择。</td><td>本次调用返回 not-ready；外部 callback 可以再次按当前屏幕恢复。</td></tr><tr><td><code>waiting_selection</code></td><td>等待 selection handler；等待用户选择的耗时不计入 ready timeout。</td><td><code>polling</code> 识别出可处理的 Codex/Claude selection。</td><td>handler 给出 choice 后转 <code>selection_resolved</code>；无 choice 转 <code>suspended</code>。</td></tr><tr><td><code>selection_resolved</code></td><td>把选择转换成 tmux actions 发送，并重置一个完整 ready 窗口。</td><td>用户选择或默认确认已解析。</td><td><code>polling</code>。</td></tr><tr><td><code>ready</code></td><td>把控制权还给调用方；调用方可以继续转发 queued input。</td><td>屏幕出现当前 runtime 的 idle/input prompt，或 timeout 被显式禁用。</td><td>调用方进入 auto-forward 的发送阶段。</td></tr><tr><td><code>missing</code></td><td>返回 not-ready，并记录 provider-owned tmux session 已消失。</td><td>抓屏失败后 <code>has-session</code> 也失败。</td><td>调用方决定是否重建、报错或发退出通知。</td></tr><tr><td><code>timeout</code></td><td>做最后一次 session 检查并返回 not-ready timeout 结果。</td><td>deadline 用完且未看到 ready prompt。</td><td>调用方按启动失败或未就绪处理。</td></tr></tbody></table><p><code>ready -&gt; running</code> 不在 readiness gate 内发生：普通消息 auto-forward 在 <code>ready</code> 返回后才发送原始 literal/Enter，并由 host manager 启动 post-forward exit probe 和 mirror 等待。<code>running -&gt; suspended</code> 也不是这个函数内部状态；它由后续 mirror probe、<code>/tmux-screen</code> 或新的 auto-forward readiness 检测再次发现 TUI selection 来表达。</p><h3 id="_3-普通消息转发" tabindex="-1">3. 普通消息转发 <a class="header-anchor" href="#_3-普通消息转发" aria-label="Permalink to &quot;3. 普通消息转发&quot;">​</a></h3><p>普通 IM 消息有两种进入 Codex tmux 的路径：</p><ul><li>已经在 interactive turn 中运行的 Codex 请求由 <code>CodexRoutingProvider</code> 根据 <code>codexProvider=tmux</code> 分发到 <code>CodexTmuxProvider</code>。provider 校验 tmux session，等待信任、更新或权限选择提示稳定后，通过 tmux core 注入 prompt。</li><li>已经绑定到 tmux provider 的聊天会在 host manager 的普通消息分支中被直接 auto-forward 到 <code>/tmux &lt;message&gt;</code>。这条路径用于“把普通聊天文本当作 TUI 输入”，会自动追加 Enter，并在 tmux session 缺失时走上一节的 auto-recover。</li></ul><p>auto-forward 的输入必须在启动门控之后才写入 tmux：缺失 session 恢复、新建 provider session、以及已存在 session 但屏幕仍停在启动 selection 的路径，都会先执行 shared ready/selection 检测。等待过程是异步 Promise，不会阻塞 Node 主事件循环；调度层会把 tmux provider 普通消息标记为 conversation barrier，阻塞同一 chat/session 的后续普通消息和 session 变更命令，直到当前 auto-forward 完成。<code>/stop</code>、selection callback 等控制路径仍可绕过 barrier，用于中断或完成启动选择。<code>/tmux-screen</code>、<code>/pty-screen</code> 保持 feature 前的 monitor job 行为：它们走 job lane 但不等待 conversation barrier，因此可在普通对话卡住时及时抓屏；<code>/shell</code> 等普通 job 仍等待 barrier。只查看或手动控制 pane 的命令不自动恢复 provider session，也不等待 startup ready。</p><p>host manager 会在 tmux provider 普通消息进入 auto-forward 时立即给原 IM 消息加 <code>Typing</code> reaction，覆盖本地 thread bootstrap、tmux session recovery、ready 检测和 selection 等待阶段。若 ready 过程中需要用户选择，<code>requestCodexTuiSelection</code> 会发送完整 IM selection card；permission broker 按 channel/chat/session/prompt 去重，startup readiness 和 mirror probe 同时看到同一个 Codex TUI selection 时只发一张卡，重复 waiter 共享同一个用户选择，并能接住 rich card 发送完成但 permission link 尚未落库时的早到回调。provider auto-forward 的 selection card 会在 permission link 元数据中保存原始 tmux actions；如果真实回调到达时 live waiter 已经丢失，host manager 的 orphan 恢复路径复用同一个 readiness gate 发送 selection choice、等待 <code>ready</code>，然后再继续发送原始 actions，避免另写一套抓屏/解析/发送选择逻辑。用户选择的等待时间不计入 shared ready timeout，选择动作发送到 tmux 后会重置一个完整 ready 窗口，因此 Codex trust/update/goal selection 和 Claude onboarding/trust prompt 都不会因为用户思考时间而触发启动失败清理。若无需选择，reaction 仍让用户知道后台正在处理。输入成功写入后，host manager 会启动一个短延迟的 post-forward exit probe：如果 JSONL mirror 开始 streaming，probe 会随 pending reaction 一起取消；如果 probe 发现 provider-owned tmux session 已消失，会移除 reaction、把 session health 标记为 failed，并向 IM 发送一句“tmux Provider 会话已退出，请 <code>/p tmux</code> 重启”的可见通知；诊断命令和 mirror 细节保留在日志里。启动期用户选择 Codex update <code>update_now</code> 后，如果更新流程关闭 tmux session，启动函数会先强制通知用户并自动重启一次同名 Codex tmux；只有重启失败或输入已成功写入后又异常退出，才落到 post-forward/update exit notice。</p><p>Codex TUI 的输出不直接依赖屏幕文本作为最终答案，而是由 Codex session JSONL mirror 同步。</p><h3 id="_4-jsonl-mirror-和回复" tabindex="-1">4. JSONL mirror 和回复 <a class="header-anchor" href="#_4-jsonl-mirror-和回复" aria-label="Permalink to &quot;4. JSONL mirror 和回复&quot;">​</a></h3><p>Codex TUI 写入本地 JSONL 后，<code>src/runtime/codex/session-index/*</code> 负责发现 session 文件、按 offset 解析增量，并转换成 <code>BridgeMirrorRecord</code>。<code>src/bridge/mirror/runtime.ts</code> 订阅活动绑定，<code>src/bridge/mirror/turns.ts</code> 合并 message、reasoning、tool、plan 和 terminal 事件，再交给反馈控制器投递到 IM。</p><h3 id="_5-卡顿和健康检测" tabindex="-1">5. 卡顿和健康检测 <a class="header-anchor" href="#_5-卡顿和健康检测" aria-label="Permalink to &quot;5. 卡顿和健康检测&quot;">​</a></h3><p>卡顿检测不依赖单一信号。<code>src/bridge/health/runtime.ts</code> 汇总 <code>BridgeSession</code> 的 <code>runtime_status</code>、<code>last_progress_at</code>、活跃工具、stream UI 刷新、mirror 事件时间和进程状态，<code>src/bridge/health/reducer.ts</code> 归约为 <code>running_active</code>、<code>slow_observed</code>、<code>suspected_stall</code>、<code>suspected_stream_ui_stall</code>、<code>suspected_detached</code> 等状态。<code>/health</code> 展示单会话诊断，<code>/status</code> 和运行时卡片展示概览。</p><h2 id="claude-tmux-生命周期" tabindex="-1">Claude tmux 生命周期 <a class="header-anchor" href="#claude-tmux-生命周期" aria-label="Permalink to &quot;Claude tmux 生命周期&quot;">​</a></h2><p>Claude Code 现在提供与 Codex tmux 对齐的 provider：</p><table tabindex="0"><thead><tr><th>阶段</th><th>Claude tmux 实现</th></tr></thead><tbody><tr><td>provider 选择</td><td><code>/provider tmux</code> 写入 <code>BridgeSession.runtime.claude.provider=tmux</code>，并记录 <code>general.tmuxSessionName</code>。</td></tr><tr><td>启动命令</td><td>shared <code>startClaudeTmuxSession</code> 复用 Claude pty 的 CLI 参数构造，支持 <code>claude</code> / <code>ccr code</code>、model、permission mode 和 <code>--effort</code>。</td></tr><tr><td>tmux session</td><td><code>claudeTmuxSessionName(session.id)</code> 生成稳定 session 名，<code>startRuntimeTmuxSession(runtime=&#39;claude&#39;)</code> 创建或重建 detached session。</td></tr><tr><td>prompt 注入</td><td><code>ClaudeTmuxProvider</code> 使用 <code>tmuxCore.injectPromptIntoPane</code> 注入普通消息。</td></tr><tr><td>会话身份</td><td>provider 通过 Claude JSONL discovery 获取 <code>session_id</code>、cwd 和 transcript path，并在 SSE <code>result</code> 中回传。</td></tr><tr><td>输出同步</td><td>Claude pty/tmux 都依赖 <code>src/runtime/claude/session-jsonl.ts</code> 读取 Claude Code JSONL；SDK provider 继续走原生事件。</td></tr></tbody></table><p>Claude tmux 与 Codex tmux 的差异是：Claude Code 本身决定 JSONL session id；CodeLark 不需要像 Codex 那样预创建 thread，也不会执行 <code>resume &lt;threadId&gt;</code>。因此 Claude tmux 的身份注入发生在 Claude Code 写出 JSONL 后，再把发现到的 <code>session_id</code> 保存回 <code>BridgeSession.runtime.claude.sessionId</code>。</p><p>Claude tmux 也必须支持和 Codex 相同的普通消息隐式初始化/恢复语义：如果当前聊天的有效 Claude provider 是 <code>tmux</code>，但还没有 <code>runtime.general.tmuxSessionName</code>，第一条普通消息会生成 <code>claude_&lt;BridgeSessionId&gt;</code> 并启动 Claude Code TUI；如果已记录 tmux session 但进程不存在，普通消息会重建同名 tmux session。两种情况都会写回 <code>runtime.claude.provider=tmux</code>、<code>runtime.general.tmuxSessionName</code> 和 tmux auto-enter 配置，然后再把消息注入 TUI。之后 <code>reconcileClaudeTmuxMirrorAfterAutoForward</code> 等待 Claude JSONL 出现，发现 <code>session_id</code> 后写回 <code>runtime.claude.sessionId/cwd</code>，prime 首个 turn 的 mirror delivery，并触发 Claude mirror reconcile。</p><p>Claude tmux 使用同一个 <code>waitForRuntimeTmuxReady</code> 启动门控。新建、恢复或已有 Claude provider-owned tmux session 在 auto-forward 前都会等待 Claude 输入提示，并会处理 onboarding/trust prompt。为兼容旧会话和测试 fake pane，Claude readiness 还接受“看起来是 TUI 且已出现输入提示、且没有任何 selection prompt”的通用 ready 兜底；这个兜底只用于 provider-owned tmux 的启动/发送路径，不影响普通 <code>/tmux-screen</code> 查看。</p><h2 id="链路对齐盘点" tabindex="-1">链路对齐盘点 <a class="header-anchor" href="#链路对齐盘点" aria-label="Permalink to &quot;链路对齐盘点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>链路点</th><th>Codex tmux</th><th>Claude tmux</th><th>当前对齐状态</th></tr></thead><tbody><tr><td>provider 选择</td><td><code>/provider tmux</code> 写 session TOML <code>runtime.codex.provider=tmux</code>。</td><td><code>/provider tmux</code> 写 session TOML <code>runtime.claude.provider=tmux</code>，并更新 runtime state。</td><td>已对齐；Claude 额外把 <code>activeRuntime</code> 固定为 <code>claude</code>。</td></tr><tr><td>本地身份</td><td>先有 Codex <code>thread_id</code>；没有时本地 bootstrap。</td><td>Claude Code 写 JSONL 后才有 <code>session_id</code>；启动前用 BridgeSessionId 命名。</td><td>语义不同但状态落点对齐：都写回 <code>BridgeSession.runtime.*</code>。</td></tr><tr><td>tmux session 命名</td><td><code>codex_&lt;thread_id&gt;</code>。</td><td><code>claude_&lt;session_id&gt;</code>；没有 Claude <code>session_id</code> 时用 <code>claude_&lt;BridgeSessionId&gt;</code>。</td><td>已对齐到统一 <code>runtimeTmuxSessionName</code> 规则。</td></tr><tr><td><code>/provider tmux</code> 启动</td><td>启动或重建 detached tmux，执行 <code>codex resume &lt;thread_id&gt;</code>。</td><td>启动或重建 detached tmux，执行 Claude Code TUI。</td><td>已对齐；启动参数各自走 runtime config。</td></tr><tr><td>普通消息隐式初始化</td><td>auto-forward 触发 <code>/tmux &lt;message&gt;</code>；缺 thread/session 时自动 bootstrap + 启动 + ready/selection 后注入。</td><td>auto-forward 触发 <code>/tmux &lt;message&gt;</code>；缺 tmux session 时自动启动 Claude TUI，session 缺失时用 BridgeSessionId 命名。</td><td>已对齐；Claude 不做 thread bootstrap，只等待 JSONL 发现身份。</td></tr><tr><td>缺失 tmux 恢复</td><td><code>/provider tmux</code> 会强制重启；普通消息 auto-forward 和显式 <code>/tmux &lt;...&gt;</code> 可重建 provider session；<code>/tmux-screen</code> 只查看并提示 <code>/p tmux</code>。</td><td><code>/provider tmux</code> 会强制重启；普通消息 auto-forward 和显式 <code>/tmux &lt;...&gt;</code> 可重建 provider session；<code>/tmux-screen</code> 只查看并提示 <code>/p tmux</code>。</td><td>已对齐；恢复范围限定在启动/发送输入路径。</td></tr><tr><td>prompt 注入</td><td>provider 内部或 <code>/tmux</code> 命令都走 tmux core；普通消息自动追加 Enter。</td><td>provider 内部或 <code>/tmux</code> 命令都走 tmux core；普通消息自动追加 Enter。</td><td>已对齐。</td></tr><tr><td>首轮 mirror</td><td>Codex thread 已知，mirror 可按 thread 找 JSONL。</td><td>首轮普通消息后等待 Claude JSONL，写回 <code>session_id/cwd</code>，再 prime 首个 turn。</td><td>已对齐到“首轮也必须可投递”，实现手段不同。</td></tr><tr><td>mirror suppression</td><td>SDK turn 复用已有 Codex JSONL thread 时建立 suppression，避免 SDK final 和 mirror final 重复。</td><td>Claude SDK provider 不订阅 tmux/pty mirror；pty/tmux 由 Claude JSONL mirror 负责最终投递。</td><td>Codex SDK/mirror 混合路径已覆盖；Claude 按 provider 分流。</td></tr><tr><td>健康状态</td><td>auto-forward 后记录 interactive start，等待 mirror terminal 更新。</td><td>auto-forward 后记录 interactive start，等待 Claude mirror terminal 更新。</td><td>已对齐。</td></tr><tr><td>TUI 特殊提示</td><td>shared readiness 检测 Codex update/goal/permission/generic selection；IM 下拉默认项跟随 TUI 当前项或第一项；所有 startup selection 都通过 IM handler 等待用户选择后继续启动门控。</td><td>shared readiness 检测 Claude onboarding/trust/input prompt，并在 provider-owned pane 上做通用 TUI ready 兜底。</td><td>已共享检测入口；按 CLI 实际提示语义分别处理默认动作。</td></tr><tr><td>auto-forward 调度门控</td><td>tmux provider 普通消息进入 session lane，并作为 conversation barrier 挡住同 chat 后续 regular/session job；control job 和 selection callback 仍可执行。</td><td>同一 adapter-runtime 机制适用于 Claude tmux provider 普通消息。</td><td>已对齐；等待 ready/selection 不阻塞 Node 主事件循环，但阻塞同一会话的后续输入。</td></tr><tr><td><code>/stop</code> / abort</td><td>tmux/pty provider 发送中断，interactive runtime 释放状态。</td><td>tmux/pty provider 发送中断，interactive runtime 释放状态。</td><td>共用终端控制和 runtime health 语义。</td></tr><tr><td><code>/clear</code> after runtime switch</td><td>只替换当前 Codex BridgeSession，保留同一聊天记住的 Claude BridgeSession 映射；清理旧 Codex provider-owned tmux session。</td><td>只替换当前 Claude BridgeSession，保留同一聊天记住的 Codex BridgeSession 映射；清理旧 Claude provider-owned tmux session。</td><td>已对齐；新 session 继承当前 active runtime 和当前 runtime 的 provider override，避免清空后静默切回另一个 runtime。</td></tr><tr><td><code>/t archive</code> cleanup</td><td>归档/删除 BridgeSession 前清理记录在 runtime state 中的 Codex tmux session。</td><td>归档/删除 BridgeSession 前清理记录在 runtime state 中的 Claude tmux session。</td><td>已对齐；只清理 provider-owned session，不清理手动 <code>/tmux-attach</code> 目标。</td></tr><tr><td><code>/t rename</code> after runtime switch</td><td>重命名当前聊天当前 Codex BridgeSession。</td><td>重命名当前聊天当前 Claude BridgeSession。</td><td>已对齐；切回另一个 runtime 时不会污染另一个 BridgeSession 的标题。</td></tr></tbody></table><h2 id="回归覆盖" tabindex="-1">回归覆盖 <a class="header-anchor" href="#回归覆盖" aria-label="Permalink to &quot;回归覆盖&quot;">​</a></h2><table tabindex="0"><thead><tr><th>覆盖点</th><th>测试</th></tr></thead><tbody><tr><td>Codex tmux 默认 provider 首条普通消息自动 bootstrap thread、启动 tmux、等待 ready、注入、mirror 投递。</td><td><code>initializes a default tmux provider conversation on first text after /set defaultProvider tmux and /new</code></td></tr><tr><td><code>/new</code> 继承 tmux provider 后首条普通消息自动初始化 Codex thread/session。</td><td><code>keeps tmux provider auto-enter enabled when /new follows /p tmux</code></td></tr><tr><td>Claude tmux 已有 tmux session 时普通消息直接注入，不走 SDK。</td><td><code>routes plain messages into Claude tmux when the active Claude provider is tmux</code></td></tr><tr><td>Claude tmux 首条普通消息自动启动 <code>claude_&lt;BridgeSessionId&gt;</code>、写回绑定、注入、发现 JSONL、启动 mirror。</td><td><code>auto-initializes a Claude tmux provider binding on the first plain message</code></td></tr><tr><td>Claude tmux 普通消息后 JSONL 出现时回填 <code>session_id/cwd</code> 并投递首个 mirror turn。</td><td><code>starts Claude tmux mirror after a plain auto-forwarded message discovers the JSONL session</code></td></tr><tr><td>切到 Claude runtime 后不会被 Codex tmux provider 抢走普通消息。</td><td><code>does not let the Codex tmux provider intercept plain messages after switching to Claude runtime</code></td></tr><tr><td>tmux provider 普通消息等待 ready/selection 时，同 chat 后续 job 被 conversation barrier 阻塞，但 <code>/stop</code> 控制消息仍可执行。</td><td><code>lets regular messages opt into a conversation barrier without blocking controls</code></td></tr><tr><td>host manager 将 tmux provider 普通消息分类为阻塞同 chat 的 tmux auto-forward session job。</td><td><code>adapterSessionLane</code> tmux regular barrier assertions</td></tr><tr><td>provider tmux auto-forward 启动时遇到无默认 Codex permission selection，fake Codex TUI 负责生成 permission prompt，fake tmux 只承载 capture/send-keys；CodeLark 会先发 IM 选择卡，用户回调后才注入 literal。</td><td><code>waits for a no-default Codex permission selection before provider tmux auto-forward input</code></td></tr><tr><td>startup readiness 与 mirror probe 同时看到同一 Codex TUI selection 时只发一张 IM 卡，用户选择会同时唤醒所有 waiter。</td><td><code>suppresses duplicate Codex TUI selection cards while resolving all waiters</code></td></tr><tr><td>Feishu <code>select_static</code> 回调即使把选项包成对象，也能提取用户实际选择并透传给 waiter。</td><td><code>extracts selected callback data from select_static object options</code></td></tr><tr><td>tmux provider 普通消息写入后 session 立刻消失时，host manager 会清理 Typing reaction、标记 health failed，并向 IM 发送退出通知。</td><td><code>notifies the chat when a tmux provider session exits right after auto-forwarded input</code></td></tr><tr><td>Codex 启动没有 update prompt 但尚未 ready 时，fake Codex TUI 先输出 starting screen；CodeLark 持续 readiness capture，直到 ready 后才把触发拉起的原始输入和 Enter 透传进 tmux。</td><td><code>does not forward the triggering input until a normal fake Codex tmux startup becomes ready</code></td></tr><tr><td>Codex 启动 update prompt 选择 <code>update_now</code> 后，fake Codex TUI 模拟更新输出和进程退出，fake tmux 只负责承载 session/capture/send-keys；CodeLark 强制提示用户、重启同名 tmux、等待 ready 后再发送原始 auto-forward 输入。</td><td><code>relaunches Codex tmux and forwards input when startup update selection exits after update_now</code></td></tr><tr><td>Codex CLI resolver 拒绝 <code>node_modules/.bin/codex</code>，要求全局 Codex CLI。</td><td><code>rejects node_modules even when it is the only Codex CLI on PATH</code></td></tr><tr><td>SDK final 与已有 Codex mirror 订阅共存时建立 suppression，避免重复 final。</td><td><code>delivers /auto SDK final output for a still-bound session without duplicate mirror output</code></td></tr><tr><td><code>/clear</code> 在 Claude runtime 下运行时保持 Claude runtime/provider，并保留同聊天 Codex runtime 映射。</td><td><code>keeps the active runtime and remembered alternate runtime when /clear follows a runtime switch</code></td></tr><tr><td><code>/t rename</code> 在 runtime 切换后只修改当前 runtime 的 BridgeSession 标题。</td><td><code>renames only the active runtime BridgeSession after runtime switches</code></td></tr><tr><td><code>/tmux-attach</code> 和 <code>/tmux-screen</code> 查看当前屏幕时通过 shared inspect 报告 selection prompt。</td><td><code>reports tmux selection prompts through shared attach and screen inspection</code></td></tr></tbody></table><h2 id="命令和配置入口" tabindex="-1">命令和配置入口 <a class="header-anchor" href="#命令和配置入口" aria-label="Permalink to &quot;命令和配置入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>入口</th><th>作用</th></tr></thead><tbody><tr><td>`/runtime codex</td><td>claude`</td></tr><tr><td><code>/provider tmux</code></td><td>对当前 runtime 启用 tmux provider。Codex 会启动 <code>codex_&lt;threadId&gt;</code>；Claude 会启动 <code>claude_&lt;session_id 或 BridgeSessionId&gt;</code>。</td></tr><tr><td>普通消息 + tmux provider</td><td>对当前 runtime 的 tmux provider 自动注入 TUI；Codex 可自动 bootstrap thread 并启动 <code>codex_&lt;threadId&gt;</code>，Claude 可自动启动或恢复 <code>claude_&lt;BridgeSessionId 或 session_id&gt;</code>。</td></tr><tr><td><code>/tmux-screen</code></td><td>查看当前绑定的 tmux 屏幕。</td></tr><tr><td><code>/stop</code></td><td>对运行中的 tmux/pty provider 发送中断。</td></tr><tr><td><code>/clear</code></td><td>清空当前聊天当前 runtime 的 BridgeSession；如果同一聊天记住了另一个 runtime 的 BridgeSession，映射会保留，之后 <code>/runtime &lt;other&gt;</code> 可以切回；旧 runtime tmux provider session 会 best-effort 清理。</td></tr><tr><td><code>/t archive ...</code></td><td>归档本地 Codex/Claude 会话或删除 Bridge-only 会话；如果目标 BridgeSession 记录了 runtime tmux provider session，会 best-effort 清理。</td></tr><tr><td><code>/t rename &lt;name&gt;</code></td><td>重命名当前聊天当前 runtime 绑定的 BridgeSession；不会改写同一聊天里另一个 runtime 的 BridgeSession 标题。</td></tr><tr><td><code>/current</code></td><td>当前会话配置卡片，支持 provider、model、mode、reasoning 等会话级覆盖。</td></tr><tr><td><code>/set codexReasoningEffort ...</code></td><td>设置 Codex 全局 reasoning 默认值。</td></tr><tr><td><code>/set claudeReasoningEffort ...</code></td><td>设置 Claude Code 全局 effort 默认值。</td></tr><tr><td>`/set claudeProvider pty</td><td>tmux</td></tr></tbody></table><h2 id="维护边界" tabindex="-1">维护边界 <a class="header-anchor" href="#维护边界" aria-label="Permalink to &quot;维护边界&quot;">​</a></h2><ul><li>tmux 命令拼装、长文本 paste、屏幕抓取和特殊键发送必须继续留在 <code>src/bridge/tmux/core.ts</code>，不要在 provider 内重复 shell 拼接。</li><li>Codex 和 Claude 各自的 CLI 参数构造可以不同，但 provider-owned tmux session 的创建、ready/selection 检测、查看和清理应通过 <code>src/bridge/tmux/runtime.ts</code> 暴露的 runtime API。</li><li>普通消息 auto-forward 和显式 <code>/tmux &lt;...&gt;</code> 的自动初始化逻辑集中在 <code>src/bridge/command/tmux.ts</code>：Codex 和 Claude 都应只在 <code>autoRecoverProviderSession=true</code> 时启动或重建 provider-owned tmux session；<code>/tmux-screen</code>、<code>/tmux-session</code> 和 <code>/tmux-attach</code> 不负责 provider 恢复，也不等待 startup ready。</li><li>tmux provider 普通消息的调度门控在 adapter runtime/host manager 层表达为 session lane + conversation barrier；不要把同 chat 阻塞语义藏进 tmux command handler 内部，否则 <code>/tmux-screen</code>、<code>/runtime</code> 等后续 job 可能绕过启动等待。</li><li>tmux provider 普通消息的可见进度、selection 去重和 post-forward/update exit notice 属于 host manager/permission broker 职责，因为它们依赖 IM adapter reaction、mirror stream start、selection callback 和 session health 多方状态；provider 只应暴露底层 tmux readiness/selection 能力，否则 Claude tmux 无法共享同一行为。</li><li>JSONL mirror 是 pty/tmux provider 的权威输出来源；屏幕抓取主要用于 ready 检测、人工诊断和短期兜底。</li><li>卡顿检测应继续消费统一的 <code>BridgeSession</code> 运行状态和 mirror 进度，而不是让 provider 自己决定最终健康状态。</li></ul>',43))])}const v=r(u,[["render",m]]);export{b as __pageData,v as default};
